from datetime import datetime, timezone
from http.server import HTTPServer, BaseHTTPRequestHandler
import json
import html


class LogSanitizer:
    """Sanitizes log messages to prevent log injection attacks."""
    
    # Pattern to match control characters, newlines, carriage returns, etc.
    CONTROL_CHAR_PATTERN = re.compile(r'[\x00-\x08\x0b\x0c\x0e-\x1f\x7f]')
    NEWLINE_PATTERN = re.compile(r'[\r\n]+')
    
    # Maximum length for individual fields to prevent log flooding
    MAX_MESSAGE_LENGTH = 4096
    MAX_FIELD_LENGTH = 256
    
    @staticmethod
    def sanitize_message(message: str) -> str:
        """Sanitize a log message to prevent injection."""
        if not isinstance(message, str):
            message = str(message)
        
        # Replace newlines and carriage returns with escaped versions
        message = LogSanitizer.NEWLINE_PATTERN.sub(' [NEWLINE] ', message)
        
        # Remove control characters
        message = LogSanitizer.CONTROL_CHAR_PATTERN.sub('', message)
        
        # Escape HTML entities to prevent XSS if logs are viewed in browser
        message = html.escape(message)
        
        # Truncate to max length
        if len(message) > LogSanitizer.MAX_MESSAGE_LENGTH:
            message = message[:LogSanitizer.MAX_MESSAGE_LENGTH] + '...[TRUNCATED]'
        
        return message
    
    @staticmethod
    def sanitize_field(field: str) -> str:
        """Sanitize a metadata field (service name, level, etc.)."""
        if not isinstance(field, str):
            field = str(field)
        
        # Replace newlines and carriage returns
        field = LogSanitizer.NEWLINE_PATTERN.sub('', field)
        
        # Remove control characters
        field = LogSanitizer.CONTROL_CHAR_PATTERN.sub('', field)
        
        # Escape HTML entities
        field = html.escape(field)
        
        # Truncate
        if len(field) > LogSanitizer.MAX_FIELD_LENGTH:
            field = field[:LogSanitizer.MAX_FIELD_LENGTH] + '...[TRUNCATED]'
        
        return field
    
    @staticmethod
    def validate_log_level(level: str) -> str:
        """Validate and normalize log level."""
        valid_levels = {'DEBUG', 'INFO', 'WARNING', 'ERROR', 'CRITICAL'}
        level_upper = level.upper().strip() if isinstance(level, str) else 'INFO'
        if level_upper not in valid_levels:
            return 'INFO'
        return level_upper
    
    @staticmethod
    def sanitize_service_name(service: str) -> str:
        """Sanitize service name - only allow alphanumeric, hyphens, underscores."""
        if not isinstance(service, str):
            service = 'unknown'
        # Only allow safe characters for service names
        sanitized = re.sub(r'[^a-zA-Z0-9_\-.]', '_', service)
        if not sanitized:
            sanitized = 'unknown'
        return sanitized[:LogSanitizer.MAX_FIELD_LENGTH]


class LogWriter:
    """Thread-safe log file writer."""
    
    def __init__(self, log_file_path: str):
        self.log_file_path = log_file_path
        self._lock = threading.Lock()
        
        # Ensure log directory exists
        log_dir = os.path.dirname(log_file_path)
        if log_dir:
            os.makedirs(log_dir, exist_ok=True)
    
    def write_log_entry(self, timestamp: str, level: str, service: str,
                        request_id: str, source_ip: str, message: str,
                        extra_fields: dict = None):
        """Write a sanitized log entry to the file."""
        # Sanitize all fields
        sanitizer = LogSanitizer
        
        safe_level = sanitizer.validate_log_level(level)
        safe_service = sanitizer.sanitize_service_name(service)
        safe_request_id = sanitizer.sanitize_field(request_id)
        safe_source_ip = sanitizer.sanitize_field(source_ip)
        safe_message = sanitizer.sanitize_message(message)
        safe_timestamp = sanitizer.sanitize_field(timestamp)
        
        # Build the log line using safe formatting
        # Using a fixed format to prevent format string injection
        log_line = "[{timestamp}] [{level}] [{service}] [{request_id}] [{source_ip}] {message}".format(
            timestamp=safe_timestamp,
            level=safe_level,
            service=safe_service,
            request_id=safe_request_id,
            source_ip=safe_source_ip,
            message=safe_message
        )
        
        # Append sanitized extra fields if present
        if extra_fields and isinstance(extra_fields, dict):
            safe_extras = {}
            for key, value in extra_fields.items():
                safe_key = sanitizer.sanitize_field(str(key))
                safe_value = sanitizer.sanitize_field(str(value))
                safe_extras[safe_key] = safe_value
            if safe_extras:
                extras_str = " | " + " | ".join(
                    "{k}={v}".format(k=k, v=v) for k, v in safe_extras.items()
                )
                log_line += extras_str
        
        # Thread-safe write
        with self._lock:
            with open(self.log_file_path, 'a', encoding='utf-8') as f:
                f.write(log_line + '\n')
                f.flush()
        
        return log_line


class LogRequestHandler(BaseHTTPRequestHandler):
    """HTTP request handler for receiving log messages."""
    
    log_writer = None  # Set by the server
    
    def do_POST(self):
        """Handle POST requests to submit log entries."""
        if self.path == '/log':
            self._handle_log_request()
        elif self.path == '/batch':
            self._handle_batch_request()
        elif self.path == '/health':
            self._send_response(200, {'status': 'healthy'})
        else:
            self._send_response(404, {'error': 'Not found'})
    
    def do_GET(self):
        """Handle GET requests for health checks."""
        if self.path == '/health':
            self._send_response(200, {'status': 'healthy'})
        else:
            self._send_response(404, {'error': 'Not found'})
    
    def _handle_log_request(self):
        """Process a single log entry request."""
        try:
            body = self._read_body()
            if body is None:
                return
            
            data = json.loads(body)
            
            if not isinstance(data, dict):
                self._send_response(400, {'error': 'Request body must be a JSON object'})
                return
            
            # Extract and validate required fields
            message = data.get('message', '')
            if not message:
                self._send_response(400, {'error': 'Missing required field: message'})
                return
            
            timestamp = data.get('timestamp', datetime.now(timezone.utc).isoformat())
            level = data.get('level', 'INFO')
            service = data.get('service', 'unknown')
            request_id = data.get('request_id', '-')
            source_ip = self.client_address[0] if self.client_address else 'unknown'
            extra_fields = data.get('extra', {})
            
            if not isinstance(extra_fields, dict):
                extra_fields = {}
            
            # Write the log entry
            log_line = self.log_writer.write_log_entry(
                timestamp=timestamp,
                level=level,
                service=service,
                request_id=request_id,
                source_ip=source_ip,
                message=message,
                extra_fields=extra_fields
            )
            
            self._send_response(200, {'status': 'logged', 'entry': log_line})
            
        except json.JSONDecodeError:
            self._send_response(400, {'error': 'Invalid JSON'})
        except Exception as e:
            self._send_response(500, {'error': 'Internal server error'})
            # Log the error internally
            self.log_writer.write_log_entry(
                timestamp=datetime.now(timezone.utc).isoformat(),
                level='ERROR',
                service='log-server',
                request_id='-',
                source_ip='localhost',
                message='Error processing log request: {}'.format(
                    LogSanitizer.sanitize_message(str(e))
                )
            )
    
    def _handle_batch_request(self):
        """Process a batch of log entries."""
        try:
            body = self._read_body()
            if body is None:
                return
            
            data = json.loads(body)
            
            if not isinstance(data, dict):
                self._send_response(400, {'error': 'Request body must be a JSON object'})
                return
            
            entries = data.get('entries', [])
            
            if not isinstance(entries, list):
                self._send_response(400, {'error': 'entries must be a list'})
                return
            
            # Limit batch size to prevent abuse
            max_batch_size = 100
            if len(entries) > max_batch_size:
                self._send_response(400, {
                    'error': 'Batch size exceeds maximum of {}'.format(max_batch_size)
                })
                return
            
            logged_count = 0
            errors = []
            source_ip = self.client_address[0] if self.client_address else 'unknown'
            
            for i, entry in enumerate(entries):
                if not isinstance(entry, dict):
                    errors.append({'index': i, 'error': 'Entry must be a JSON object'})
                    continue
                
                message = entry.get('message', '')
                if not message:
                    errors.append({'index': i, 'error': 'Missing message'})
                    continue
                
                timestamp = entry.get('timestamp', datetime.now(timezone.utc).isoformat())
                level = entry.get('level', 'INFO')
                service = entry.get('service', 'unknown')
                request_id = entry.get('request_id', '-')
                extra_fields = entry.get('extra', {})
                
                if not isinstance(extra_fields, dict):
                    extra_fields = {}
                
                self.log_writer.write_log_entry(
                    timestamp=timestamp,
                    level=level,
                    service=service,
                    request_id=request_id,
                    source_ip=source_ip,
                    message=message,
                    extra_fields=extra_fields
                )
                logged_count += 1
            
            response = {
                'status': 'processed',
                'logged': logged_count,
                'errors': errors
            }
            self._send_response(200, response)
            
        except json.JSONDecodeError:
            self._send_response(400, {'error': 'Invalid JSON'})
        except Exception as e:
            self._send_response(500, {'error': 'Internal server error'})
            self.log_writer.write_log_entry(
                timestamp=datetime.now(timezone.utc).isoformat(),
                level='ERROR',
                service='log-server',
                request_id='-',
                source_ip='localhost',
                message='Error processing batch request: {}'.format(
                    LogSanitizer.sanitize_message(str(e))
                )
            )
    
    def _read_body(self):
        """Read and validate the request body."""
        content_length = self.headers.get('Content-Length')
        if content_length is None:
            self._send_response(411, {'error': 'Content-Length required'})
            return None
        
        try:
            content_length = int(content_length)
        except ValueError:
            self._send_response(400, {'error': 'Invalid Content-Length'})
            return None
        
        # Limit request body size (1MB)
        max_body_size = 1 * 1024 * 1024
        if content_length > max_body_size:
            self._send_response(413, {'error': 'Request body too large'})
            return None
        
        body = self.rfile.read(content_length)
        return body.decode('utf-8', errors='replace')
    
    def _send_response(self, status_code: int, data: dict):
        """Send a JSON response."""
        response_body = json.dumps(data).encode('utf-8')
        self.send_response(status_code)
        self.send_header('Content-Type', 'application/json')
        self.send_header('Content-Length', str(len(response_body)))
        self.end_headers()
        self.wfile.write(response_body)
    
    def log_message(self, format, *args):
        """Override to prevent default stderr logging and log to our file instead."""
        if self.log_writer:
            self.log_writer.write_log_entry(
                timestamp=datetime.now(timezone.utc).isoformat(),
                level='INFO',
                service='log-server',
                request_id='-',
                source_ip=self.client_address[0] if self.client_address else 'unknown',
                message='HTTP: {}'.format(LogSanitizer.sanitize_message(format % args))
            )


class CentralizedLogServer:
    """Centralized logging server for microservices."""
    
    def __init__(self, host: str = '0.0.0.0', port: int = 8080,
                 log_file: str = 'logs/centralized.log'):
        self.host = host
        self.port = port
        self.log_writer = LogWriter(log_file)
        
        # Configure the handler with our log writer
        LogRequestHandler.log_writer = self.log_writer
        
        self.server = HTTPServer((host, port), LogRequestHandler)
    
    def start(self):
        """Start the logging server."""
        self.log_writer.write_log_entry(
            timestamp=datetime.now(timezone.utc).isoformat(),
            level='INFO',
            service='log-server',
            request_id='-',
            source_ip='localhost',
            message='Centralized log server starting on {}:{}'.format(self.host, self.port)
        )
        print('Centralized Log Server running on {}:{}'.format(self.host, self.port))
        print('Endpoints:')
        print('  POST /log    - Submit a single log entry')
        print('  POST /batch  - Submit multiple log entries')
        print('  GET  /health - Health check')
        
        try:
            self.server.serve_forever()
        except KeyboardInterrupt:
            self.log_writer.write_log_entry(
                timestamp=datetime.now(timezone.utc).isoformat(),
                level='INFO',
                service='log-server',
                request_id='-',
                source_ip='localhost',
                message='Log server shutting down'
            )
            self.server.shutdown()
            print('\nServer stopped.')


